import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"壮烈成仁","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/壮烈成仁.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/壮烈成仁.md"}'),o={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/壮烈成仁.md"};function p(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"壮烈成仁",tabindex:"-1"},[n("壮烈成仁 "),r("a",{class:"header-anchor",href:"#壮烈成仁","aria-label":'Permalink to "壮烈成仁"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调018")])])],-1),s('<h1 id="壮烈成仁-1" tabindex="-1">壮烈成仁 <a class="header-anchor" href="#壮烈成仁-1" aria-label="Permalink to &quot;壮烈成仁&quot;">​</a></h1><p>壮烈成仁</p><p>A+4800<br> 描述：这是一个仅有上半身、躯体各处长满眼睛的类人型替身，替身的下半部分是散乱的紫色条带。<br> 替身数据：<br> 破坏力 B<br> 速度 E<br> 射程 B<br> 持续力A<br> 精密度 E<br> 成长性 D</p><p>需要注意的是，壮烈成仁的替身攻击的射程范围取决于你的触及范围而非替身的。</p><p>替身主属性：决心</p><p>替身能力：</p><p>【极速老化】：你可以一个标准动作令替身开始放出无形的衰老瘴气，这会令你敏感范围内的圆形区域从下一轮开始具有如下效果：<br> 1、处于该区域内的所有单位在结束自身回合时，寿命上限减少20年。至多令受影响单位的寿命降低至寿命上限的一半。<br> 2、处于该区域内的所有单位在距离你不超过决心*10米的位置结束自身回合时，寿命上限追加减少10年。至多令受影响单位的寿命降低至寿命上限的一半。<br> 3、处于该区域内的所有单位在进行的动作中若具有肢体成分，则根据动作的等级承受额外的寿命上限减值：<br> 整轮动作：30年<br> 标准动作：20年<br> 杂技动作：15年<br> 移动动作：10年<br> 迅捷/反射动作：5年<br> 花招动作：1年<br> 这至多令受影响单位的寿命降低至寿命上限的一半。<br> 4、你的肉搏攻击或者替身攻击在命中后可令目标减少所有剩余寿命。<br> 5、当使用者在一轮内处于一个位置不曾移动，则在这一轮结束后，此区域的范围扩大使用者的决心*10米，至多扩大决心*100米的距离。<br> 需要注意的是，即使有单位处于封闭空间中或是其他方式享受了全遮蔽等效果，只要这一封闭空间不具有【三防】或者是异空间特性，该单位依然会受到这一衰老效果的影响。理所当然的，一个单位不会因为穿戴了具有三防特性的护甲而免疫衰老。<br> 特殊的，使用者可以在释放气体时可以选择一个高于0度的标准温度，令此能力的衰老效果仅对自身温度高于此标准温度的单位生效。<br> 你可以选择这个能力对绝对零度以上的单位都生效，但这意味着你也在受影响单位的范围内。<br> 以上均是一个A级别、毒素来源的衰老效果。<br> 替身能力可以一个自由动作解除，或者持续至多一场景/15分钟。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
